// Auto-fix user ban status and test
export const autoFixUserBan = async () => {
  console.log('🔧 Auto-fixing user ban status...');

  // Step 1: Clear all cache immediately
  console.log('🧹 Step 1: Clearing cache...');
  localStorage.clear();
  sessionStorage.clear();

  // Step 2: Wait for cache to clear
  await new Promise(resolve => setTimeout(resolve, 2000));

  // Step 3: Check if user is logged in
  const token = localStorage.getItem('token');
  if (!token) {
    console.log('❌ No token found. User needs to login.');
    console.log('🔄 Redirecting to login page...');
    globalThis.location.href = '/login';
    return;
  }

  console.log('✅ Token found, testing profile...');

  // Step 4: Test profile endpoint
  try {
    const response = await fetch('http://localhost:8083/api/users/profile', {
      headers: { 
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      }
    });

    if (response.ok) {
      const data = await response.json();
      console.log('📊 Profile Response:', data);

      // Step 5: Analyze user status
      const canFile = data.canSubmitComplaints;
      const isBanned = data.isBanned;
      const strikeCount = data.strikeCount || 0;

      console.log('🎯 User Status Analysis:');
      console.log(`  - Can file complaints: ${canFile}`);
      console.log(`  - Is banned: ${isBanned}`);
      console.log(`  - Strike count: ${strikeCount}`);
      console.log(`  - Enabled: ${data.enabled}`);

      // Step 6: Determine if user is fixed
      if (canFile && !isBanned && strikeCount === 0) {
        console.log('✅ SUCCESS: User is unbanned and can file complaints!');
        console.log('🔄 Refreshing dashboard to show updated status...');

        // Trigger dashboard refresh
        if (window.location.pathname.includes('/dashboard')) {
          window.location.reload();
        } else {
          window.location.href = '/dashboard';
        }
      } else {
        console.log('⚠️ User still has restrictions:');
        if (isBanned) console.log('  - User is still banned');
        if (!canFile) console.log('  - User cannot file complaints');
        if (strikeCount > 0) console.log(`  - User has ${strikeCount} strikes`);

        console.log('🔧 Possible solutions:');
        console.log('  1. Check if database was updated correctly');
        console.log('  2. Restart backend server');
        console.log('  3. Contact administrator');
      }
    } else {
      console.log('❌ Profile endpoint failed:', response.status);
      console.log('🔄 Backend might be down or user session expired');

      // Clear token and redirect to login
      localStorage.removeItem('token');
      setTimeout(() => {
        window.location.href = '/login';
      }, 2000);
    }
  } catch (error) {
    console.log('❌ Error testing profile:', error);
    console.log('🔄 Network error, retrying in 3 seconds...');

    setTimeout(() => {
      autoFixUserBan();
    }, 3000);
  }
};

// Auto-expose and run immediately
if (typeof window !== 'undefined') {
  window.autoFixUser = autoFixUserBan;

  console.log('🚀 Auto-fix user ban utility loaded!');
  console.log('📝 Run: autoFixUser() to fix user ban status');

  // Auto-run after 1 second
  setTimeout(() => {
    console.log('🏃 Auto-running ban fix...');
    autoFixUserBan();
  }, 1000);
}
